import{_ as a,o as t,c as r,a0 as c}from"./chunks/framework.DgPozsi0.js";const f=JSON.parse('{"title":"[React官網] React 19.2 教程","description":"","frontmatter":{"title":"[React官網] React 19.2 教程","outline":2},"headers":[],"relativePath":"pages/f2e/docReact/reactDev/reactDev_04.md","filePath":"pages/f2e/docReact/reactDev/reactDev_04.md"}'),o={name:"pages/f2e/docReact/reactDev/reactDev_04.md"};function l(i,e,s,h,d,n){return t(),r("div",null,[...e[0]||(e[0]=[c('<h1 id="react-compiler" tabindex="-1">React Compiler <a class="header-anchor" href="#react-compiler" aria-label="Permalink to &quot;React Compiler&quot;">​</a></h1><h2 id="介紹" tabindex="-1">介紹 <a class="header-anchor" href="#介紹" aria-label="Permalink to &quot;介紹&quot;">​</a></h2><p>學習 <a href="/vitepress-study/pages/f2e/docReact/reactDev/04/reactDev_04_01.html">React 編譯器的作用</a> 以及它如何透過自動處理記憶化（<code>memoization</code>）來優化你的 <code>React</code> 應用，從而無需再手動使用 <code>useMemo</code>，<code>useCallback</code>，和 <code>React.memo</code>。</p><h2 id="安裝" tabindex="-1">安裝 <a class="header-anchor" href="#安裝" aria-label="Permalink to &quot;安裝&quot;">​</a></h2><p>開始使用與 <a href="/vitepress-study/pages/f2e/docReact/reactDev/04/reactDev_04_02.html">安裝 React 編譯器</a> 並學習如何配置你的建構工具以集成它。</p><h2 id="漸進式採用" tabindex="-1">漸進式採用 <a class="header-anchor" href="#漸進式採用" aria-label="Permalink to &quot;漸進式採用&quot;">​</a></h2><p>如果你尚未準備好在整個項目中啟用，學習 <a href="/vitepress-study/pages/f2e/docReact/reactDev/04/reactDev_04_03.html">漸進式採用 React 編編譯器的策略</a>，在現有代碼庫中逐步引入它。</p><h2 id="調試與故障排除" tabindex="-1">調試與故障排除 <a class="header-anchor" href="#調試與故障排除" aria-label="Permalink to &quot;調試與故障排除&quot;">​</a></h2><p>當程序未按預期工作時，使用我們的 <a href="/vitepress-study/pages/f2e/docReact/reactDev/04/reactDev_04_04.html">調試指南</a> 以理解編譯器錯誤和運行時問題的區別，識別常見的破壞性模式，並遵循系統化的調試流程。</p><h2 id="配置與參考" tabindex="-1">配置與參考 <a class="header-anchor" href="#配置與參考" aria-label="Permalink to &quot;配置與參考&quot;">​</a></h2><p>有關詳細的配置選項和 API 參考：</p><ul><li><a href="https://zh-hans.react.dev/reference/react-compiler/configuration" target="_blank" rel="noreferrer">配置選項</a> - 包含所有編譯器配置選項，包括 React 版本兼容性</li><li><a href="https://zh-hans.react.dev/reference/react-compiler/directives" target="_blank" rel="noreferrer">指令</a> - 用於函數級別的編譯控制</li><li><a href="https://zh-hans.react.dev/reference/react-compiler/directives" target="_blank" rel="noreferrer">編譯庫</a> - 提供預編譯的庫</li></ul><h2 id="額外的資源" tabindex="-1">額外的資源 <a class="header-anchor" href="#額外的資源" aria-label="Permalink to &quot;額外的資源&quot;">​</a></h2><p>除了本文檔之外，我們建議你關注 <a href="https://github.com/reactwg/react-compiler" target="_blank" rel="noreferrer">React 編譯器工作組</a>，以獲取有關編譯器的更多信息和討論。</p>',14)])])}const _=a(o,[["render",l]]);export{f as __pageData,_ as default};
